mapper.select:
SELECT a.account_id AS id, a.account_name AS name, a.email AS email, r.role_name AS role, a.account_status AS account_status, a.tenant_id AS tenant_id, a.seller_id AS seller_id, a.warehouse_id AS warehouse_id, a.worker_code AS worker_code, a.last_login_at AS last_login_at, a.created_at AS created_at FROM account a INNER JOIN role r ON r.role_id = a.role_id
a.tenant_id = #{tenantId}
AND r.role_name = #{roleName}
AND a.account_status = #{accountStatus}
AND ( a.account_name LIKE CONCAT('%', #{keyword}, '%') OR a.email LIKE CONCAT('%', #{keyword}, '%') OR a.worker_code LIKE CONCAT('%', #{keyword}, '%') )
ORDER BY a.created_at DESC, a.account_id ASC
